1	#pragma once
2	/********************************************************************
3	 * MultiQueue Implementation
4	 *
5	 * Originally authored by Guozheng Zhang, Gilead Posluns, and Mark C. Jeffrey
6	 * Published at the 36th ACM Symposium on Parallelism in Algorithms and
7	 * Architectures (SPAA), June 2024
8	 *
9	 * Original source: https://github.com/mcj-group/cps
10	 *
11	 * This implementation and interface has been modified from the original to:
12	 *   - Support queue draining functionality
13	 *   - Enable integration with the VTR project
14	 *
15	 * The MultiQueue data structure provides an efficient concurrent priority
16	 * queue implementation designed for parallel processing applications.
17	 *
18	 * Modified: February 2025
19	 ********************************************************************/
20	
21	#include "device_grid.h"
22	#include "heap_type.h"
23	#include "multi_queue_d_ary_heap.tpp"
24	#include <tuple>
25	#include <memory>
26	
27	// FIXME: Use unified heap node struct (HeapNodeId) and comparator (HeapNodeComparator)
28	// defined in heap_type.h. Currently, the MQ_IO is not compatible with them. Need a lot
29	// of refactoring in MQ_IO to make it work, which is left for another PR to clean it up.
30	using MQHeapNode = std::tuple<HeapNodePriority, uint32_t /* FIXME: Use HeapNodeId */>;
31	
32	struct MQHeapNodeTupleComparator /* FIXME: Use HeapNodeComparator */ {
33	    bool operator()(const MQHeapNode& u, const MQHeapNode& v) {
34	        return std::get<0>(u) > std::get<0>(v);
35	    }
36	};
37	
38	template<unsigned D>
39	class MultiQueueDAryHeap {
40	  public:
41	    using MQ_IO = MultiQueueIO<D, MQHeapNode, MQHeapNodeTupleComparator, HeapNodePriority>;
42	
43	    MultiQueueDAryHeap() {
44	        set_num_threads_and_queues(1, 2); // Serial (#threads=1, #queues=2) by default
45	    }
46	
47	    MultiQueueDAryHeap(size_t num_threads, size_t num_queues) {
48	        set_num_threads_and_queues(num_threads, num_queues);
49	    }
50	
51	    ~MultiQueueDAryHeap() {}
52	
53	    void set_num_threads_and_queues(size_t num_threads, size_t num_queues) {
54	        pq_.reset();
55	        // Note: BE AWARE that in MQ_IO interface, `num_queues` comes first, then `num_threads`!
56	        pq_ = std::make_unique<MQ_IO>(num_queues, num_threads, 0 /*Dont care (batch size for only popBatch)*/);
57	    }
58	
59	    void init_heap(const DeviceGrid& grid) {
60	        (void)grid;
61	        // TODO: Reserve storage for MQ_IO
62	        // Note: This function could be called before setting num_threads/num_queues
63	    }
64	
65	    bool try_pop(HeapNode& heap_node) {
66	        auto tmp = pq_->tryPop();
67	        if (!tmp.has_value()) {
68	            return false;
69	        } else {
70	            uint32_t node_id;
71	            std::tie(heap_node.prio, node_id) = tmp.value(); // FIXME: eliminate type cast by modifying MQ_IO
72	            heap_node.node = RRNodeId(node_id);
73	            return true;
74	        }
75	    }
76	
77	    void add_to_heap(const HeapNode& heap_node) {
78	        HeapNodePriority prio = heap_node.prio;
79	        uint32_t node = size_t(heap_node.node);
80	        pq_->push({prio, node});
81	    }
82	
