#pragma once
/********************************************************************
 * MultiQueue Implementation
 *
 * Originally authored by Guozheng Zhang, Gilead Posluns, and Mark C. Jeffrey
 * Published at the 36th ACM Symposium on Parallelism in Algorithms and
 * Architectures (SPAA), June 2024
 *
 * Original source: https://github.com/mcj-group/cps
 *
 * This implementation and interface has been modified from the original to:
 *   - Support queue draining functionality
 *   - Enable integration with the VTR project
 *
 * The MultiQueue data structure provides an efficient concurrent priority
 * queue implementation designed for parallel processing applications.
 *
 * Modified: February 2025
 ********************************************************************/

#include "device_grid.h"
#include "heap_type.h"
#include "multi_queue_d_ary_heap.tpp"
#include <tuple>
#include <memory>

// FIXME: Use unified heap node struct (HeapNodeId) and comparator (HeapNodeComparator)
// defined in heap_type.h. Currently, the MQ_IO is not compatible with them. Need a lot
// of refactoring in MQ_IO to make it work, which is left for another PR to clean it up.
using MQHeapNode = std::tuple<HeapNodePriority, uint32_t /* FIXME: Use HeapNodeId */>;

struct MQHeapNodeTupleComparator /* FIXME: Use HeapNodeComparator */ {
    bool operator()(const MQHeapNode& u, const MQHeapNode& v) {
        return std::get<0>(u) > std::get<0>(v);
    }
};

template<unsigned D>
class MultiQueueDAryHeap {
  public:
    using MQ_IO = MultiQueueIO<D, MQHeapNode, MQHeapNodeTupleComparator, HeapNodePriority>;

    MultiQueueDAryHeap() {
        set_num_threads_and_queues(1, 2); // Serial (#threads=1, #queues=2) by default
    }

    MultiQueueDAryHeap(size_t num_threads, size_t num_queues) {
        set_num_threads_and_queues(num_threads, num_queues);
    }

    ~MultiQueueDAryHeap() {}

    void set_num_threads_and_queues(size_t num_threads, size_t num_queues) {
        pq_.reset();
        // Note: BE AWARE that in MQ_IO interface, `num_queues` comes first, then `num_threads`!
        pq_ = std::make_unique<MQ_IO>(num_queues, num_threads, 0 /*Dont care (batch size for only popBatch)*/);
    }

    void init_heap(const DeviceGrid& grid) {
        (void)grid;
        // TODO: Reserve storage for MQ_IO
        // Note: This function could be called before setting num_threads/num_queues
    }

    bool try_pop(HeapNode& heap_node) {
        auto tmp = pq_->tryPop();
        if (!tmp.has_value()) {
            return false;
        } else {
            uint32_t node_id;
            std::tie(heap_node.prio, node_id) = tmp.value(); // FIXME: eliminate type cast by modifying MQ_IO
            heap_node.node = RRNodeId(node_id);
            return true;
        }
    }

    void add_to_heap(const HeapNode& heap_node) {
        HeapNodePriority prio = heap_node.prio;
        uint32_t node = size_t(heap_node.node);
        pq_->push({prio, node});
    }

    void push_back(const HeapNode& heap_node) {
        HeapNodePriority prio = heap_node.prio;
        uint32_t node = size_t(heap_node.node);
        pq_->push({prio, node}); // FIXME: add to heap without maintaining the heap property
    }

    void build_heap() {
        // FIXME: restore the heap property after pushing back nodes
    }

    bool is_valid() const {
        return true; // FIXME: checking if the heap property is maintained or not
    }

    void empty_heap() {
        pq_->reset(); // TODO: check if adding clear function for MQ_IO is necessary
    }

    bool is_empty_heap() const {
        return (bool)(pq_->empty());
    }

    uint64_t get_num_pushes() const {
        return pq_->getNumPushes();
    }

    uint64_t get_num_pops() const {
        return pq_->getNumPops();
    }

    uint64_t get_heap_occupancy() const {
        return pq_->getQueueOccupancy();
    }

    void reset() {
        pq_->reset();
    }

#ifdef MQ_IO_ENABLE_CLEAR_FOR_POP
    void set_min_priority_for_pop(const HeapNodePriority& minPrio) {
        pq_->setMinPrioForPop(minPrio);
    }
#endif

  private:
    std::unique_ptr<MQ_IO> pq_;
};

#pragma once
/** @file Interface for a netlist router.
 *
 * A NetlistRouter manages the required bits of state to complete the netlist routing process,
 * which requires finding a path for every connection in the netlist using a SerialConnectionRouter.
 * This needs to be an interface because there may be different netlist routing schedules,
 * i.e. parallel or net-decomposing routers.
 *
 * Includes derived classes of NetlistRouter and a fn to provide the correct NetlistRouter
 * for given router options.
 *
 * NetlistRouter impls are typically templated by HeapType, since the single implementation
 * of ConnectionRouterInterface is templated by a heap type at the moment. Any templated
 * NetlistRouter-derived class is still a NetlistRouter, so that is transparent to the user
 * of this interface. */

#include <vector>
#include "NetPinTimingInvalidator.h"
#include "clustered_netlist_utils.h"
#include "connection_based_routing_fwd.h"
#include "d_ary_heap.h"
#include "heap_type.h"
#include "netlist_fwd.h"
#include "routing_predictor.h"
#include "route_budgets.h"
#include "router_stats.h"
#include "timing_info.h"
#include "vpr_net_pins_matrix.h"
#include "vpr_types.h"

/** Results for a single netlist routing run inside a routing iteration. */
struct RouteIterResults {
    /** Are there any connections impossible to route due to a disconnected rr_graph? */
    bool is_routable = true;
    /** Net IDs with changed routing */
    std::vector<ParentNetId> rerouted_nets;
    /** Net IDs with changed bounding box for this iteration.
     * Used by the parallel router to update the \ref PartitionTree */
    std::vector<ParentNetId> bb_updated_nets;
    /** RouterStats for this iteration */
    RouterStats stats;
};

/** Route a given netlist. Takes a big context and passes it around to net & sink routing fns.
 * route_netlist only needs to call the functions in route_net.h/tpp: they handle the global
 * bookkeeping. */
class NetlistRouter {
  public:
    virtual ~NetlistRouter() {}

    /** Run a single iteration of netlist routing for this->_net_list. This usually means calling
     * route_net for each net, which will handle other global updates.
     * \return RouteIterResults for this iteration. */
    virtual RouteIterResults route_netlist(int itry, float pres_fac, float worst_neg_slack) = 0;

    /** Handle net bounding box updates by passing them to the PartitionTree.
     * No-op for the serial router */
    virtual void handle_bb_updated_nets(const std::vector<ParentNetId>& nets) = 0;

    /** Enable RCV for each of the ConnectionRouters this NetlistRouter manages.*/
    virtual void set_rcv_enabled(bool x) = 0;

    /** Set this NetlistRouter's timing_info ptr. We sometimes change timing_info
     * throughout iterations, but not frequently enough to make it a public member. */
    virtual void set_timing_info(std::shared_ptr<SetupHoldTimingInfo> timing_info) = 0;
};

/* Include the derived classes here to get the HeapType-templated impls */
#include "SerialNetlistRouter.h"
#include "NestedNetlistRouter.h"
#ifdef VPR_USE_TBB
#include "ParallelNetlistRouter.h"
#include "DecompNetlistRouter.h"
#endif

template<typename HeapType>
inline std::unique_ptr<NetlistRouter> make_netlist_router_with_heap(
    const Netlist<>& net_list,
    const RouterLookahead* router_lookahead,
    const t_router_opts& router_opts,
    CBRR& connections_inf,
    NetPinsMatrix<float>& net_delay,
    const ClusteredPinAtomPinsLookup& netlist_pin_lookup,
    std::shared_ptr<SetupHoldTimingInfo> timing_info,
    NetPinTimingInvalidator* pin_timing_invalidator,
    route_budgets& budgeting_inf,
    const RoutingPredictor& routing_predictor,
    const vtr::vector<ParentNetId, std::vector<std::unordered_map<RRNodeId, int>>>& choking_spots,
    bool is_flat,
    int route_verbosity) {
    if (router_opts.router_algorithm == e_router_algorithm::TIMING_DRIVEN) {
        return std::make_unique<SerialNetlistRouter<HeapType>>(
            net_list,
            router_lookahead,
            router_opts,
            connections_inf,
            net_delay,
            netlist_pin_lookup,
            timing_info,
            pin_timing_invalidator,
            budgeting_inf,
            routing_predictor,
            choking_spots,
            is_flat,
            route_verbosity);
    } else if (router_opts.router_algorithm == e_router_algorithm::NESTED) {
        return std::make_unique<NestedNetlistRouter<HeapType>>(
            net_list,
            router_lookahead,
            router_opts,
            connections_inf,
            net_delay,
            netlist_pin_lookup,
            timing_info,
            pin_timing_invalidator,
            budgeting_inf,
            routing_predictor,
            choking_spots,
            is_flat,
            route_verbosity);
    } else if (router_opts.router_algorithm == e_router_algorithm::PARALLEL) {
#ifdef VPR_USE_TBB
        return std::make_unique<ParallelNetlistRouter<HeapType>>(
            net_list,
            router_lookahead,
            router_opts,
            connections_inf,
            net_delay,
            netlist_pin_lookup,
            timing_info,
            pin_timing_invalidator,
            budgeting_inf,
            routing_predictor,
            choking_spots,
            is_flat,
            route_verbosity);
#else
        VPR_FATAL_ERROR(VPR_ERROR_ROUTE, "VPR isn't compiled with TBB support required for parallel routing");
#endif
    } else if (router_opts.router_algorithm == e_router_algorithm::PARALLEL_DECOMP) {
#ifdef VPR_USE_TBB
        return std::make_unique<DecompNetlistRouter<HeapType>>(
            net_list,
            router_lookahead,
            router_opts,
            connections_inf,
            net_delay,
            netlist_pin_lookup,
            timing_info,
            pin_timing_invalidator,
            budgeting_inf,
            routing_predictor,
            choking_spots,
            is_flat,
            route_verbosity);
#else
        VPR_FATAL_ERROR(VPR_ERROR_ROUTE, "VPR isn't compiled with TBB support required for parallel routing");
#endif
    } else {
        VPR_FATAL_ERROR(VPR_ERROR_ROUTE, "Unknown router algorithm %d", router_opts.router_algorithm);
    }
}

/** Make a NetlistRouter depending on router_algorithm and router_heap in \p router_opts. */
inline std::unique_ptr<NetlistRouter> make_netlist_router(
    const Netlist<>& net_list,
    const RouterLookahead* router_lookahead,
    const t_router_opts& router_opts,
    CBRR& connections_inf,
    NetPinsMatrix<float>& net_delay,
    const ClusteredPinAtomPinsLookup& netlist_pin_lookup,
    std::shared_ptr<SetupHoldTimingInfo> timing_info,
    NetPinTimingInvalidator* pin_timing_invalidator,
    route_budgets& budgeting_inf,
    const RoutingPredictor& routing_predictor,
    const vtr::vector<ParentNetId, std::vector<std::unordered_map<RRNodeId, int>>>& choking_spots,
    bool is_flat,
    int route_verbosity) {
    if (router_opts.router_heap == e_heap_type::BINARY_HEAP) {
        return make_netlist_router_with_heap<BinaryHeap>(
            net_list,
            router_lookahead,
            router_opts,
            connections_inf,
            net_delay,
            netlist_pin_lookup,
            timing_info,
            pin_timing_invalidator,
            budgeting_inf,
            routing_predictor,
            choking_spots,
            is_flat,
            route_verbosity);
    } else if (router_opts.router_heap == e_heap_type::FOUR_ARY_HEAP) {
        return make_netlist_router_with_heap<FourAryHeap>(
            net_list,
            router_lookahead,
            router_opts,
            connections_inf,
            net_delay,
            netlist_pin_lookup,
            timing_info,
            pin_timing_invalidator,
            budgeting_inf,
            routing_predictor,
            choking_spots,
            is_flat,
            route_verbosity);
    } else {
        VPR_FATAL_ERROR(VPR_ERROR_ROUTE, "Unknown heap type %d", router_opts.router_heap);
    }
}

