#pragma once

/** @file Impls for ParallelNetlistRouter */

#include <string>
#include "netlist_routers.h"
#include "route_net.h"
#include "vtr_time.h"

template<typename HeapType>
inline RouteIterResults ParallelNetlistRouter<HeapType>::route_netlist(int itry, float pres_fac, float worst_neg_slack) {
    /* Reset results for each thread */
    for (auto& results : _results_th) {
        results = RouteIterResults();
    }

    /* Set the routing parameters: they won't change until the next call and that saves us the trouble of passing them around */
    _itry = itry;
    _pres_fac = pres_fac;
    _worst_neg_slack = worst_neg_slack;

    /* Organize netlist into a PartitionTree.
     * Nets in a given level of nodes are guaranteed to not have any overlapping bounding boxes, so they can be routed in parallel. */
    vtr::Timer timer;
    if (!_tree) {
        _tree = PartitionTree(_net_list);
        PartitionTreeDebug::log("Iteration " + std::to_string(itry) + ": built partition tree in " + std::to_string(timer.elapsed_sec()) + " s");
    }

    /* Put the root node on the task queue, which will add its child nodes when it's finished. Wait until the entire tree gets routed. */
    tbb::task_group group;
    route_partition_tree_node(group, _tree->root());
    group.wait();
    PartitionTreeDebug::log("Routing all nets took " + std::to_string(timer.elapsed_sec()) + " s");

    /* Combine results from threads */
    RouteIterResults out;
    for (auto& results : _results_th) {
        out.stats.combine(results.stats);
        out.rerouted_nets.insert(out.rerouted_nets.end(), results.rerouted_nets.begin(), results.rerouted_nets.end());
        out.bb_updated_nets.insert(out.bb_updated_nets.end(), results.bb_updated_nets.begin(), results.bb_updated_nets.end());
        out.is_routable &= results.is_routable;
    }
    return out;
}

template<typename HeapType>
void ParallelNetlistRouter<HeapType>::route_partition_tree_node(tbb::task_group& g, PartitionTreeNode& node) {
    auto& route_ctx = g_vpr_ctx.mutable_routing();

    /* node.nets is an unordered set, copy into vector to sort */
    std::vector<ParentNetId> nets(node.nets.begin(), node.nets.end());

    /* Sort so net with most sinks is routed first. */
    std::stable_sort(nets.begin(), nets.end(), [&](ParentNetId id1, ParentNetId id2) -> bool {
        return _net_list.net_sinks(id1).size() > _net_list.net_sinks(id2).size();
    });

    vtr::Timer timer;
    for (auto net_id : nets) {
        auto flags = route_net(
            _routers_th.local(),
            _net_list,
            net_id,
            _itry,
            _pres_fac,
            _router_opts,
            _connections_inf,
            _results_th.local().stats,
            _net_delay,
            _netlist_pin_lookup,
            _timing_info.get(),
            _pin_timing_invalidator,
            _budgeting_inf,
            _worst_neg_slack,
            _routing_predictor,
            _choking_spots[net_id],
            _is_flat,
            route_ctx.route_bb[net_id]);

        if (!flags.success && !flags.retry_with_full_bb) {
            /* Disconnected RRG and SerialConnectionRouter doesn't think growing the BB will work */
            _results_th.local().is_routable = false;
            return;
        }
        if (flags.retry_with_full_bb) {
            /* SerialConnectionRouter thinks we should grow the BB. Do that and leave this net unrouted for now */
            route_ctx.route_bb[net_id] = full_device_bb();
            _results_th.local().bb_updated_nets.push_back(net_id);
            continue;
        }
        if (flags.was_rerouted) {
            _results_th.local().rerouted_nets.push_back(net_id);
        }
    }

    PartitionTreeDebug::log("Node with " + std::to_string(node.nets.size())
                            + " nets and " + std::to_string(node.vnets.size())
                            + " virtual nets routed in " + std::to_string(timer.elapsed_sec())
                            + " s");

    /* This node is finished: add left & right branches to the task queue */
    if (node.left && node.right) {
        g.run([&]() {
            route_partition_tree_node(g, *node.left);
        });
        g.run([&]() {
            route_partition_tree_node(g, *node.right);
        });
    } else {
        VTR_ASSERT(!node.left && !node.right); // there shouldn't be a node with a single branch
    }
}

template<typename HeapType>
void ParallelNetlistRouter<HeapType>::handle_bb_updated_nets(const std::vector<ParentNetId>& nets) {
    VTR_ASSERT(_tree);
    _tree->update_nets(nets);
}

template<typename HeapType>
void ParallelNetlistRouter<HeapType>::set_rcv_enabled(bool x) {
    for (auto& router : _routers_th) {
        router.set_rcv_enabled(x);
    }
}

template<typename HeapType>
void ParallelNetlistRouter<HeapType>::set_timing_info(std::shared_ptr<SetupHoldTimingInfo> timing_info) {
    _timing_info = timing_info;
}

#pragma once

#include <cstdint>
#include "device_grid.h"
#include "rr_graph_fwd.h"

using HeapNodePriority = float;
using HeapNodeId = RRNodeId;
// Ensure that the heap node structure occupies only 64 bits to make the heap cache-friendly
// and achieve high performance.
static_assert(sizeof(RRNodeId) == sizeof(uint32_t));

/**
 * @brief Used by the heap as its fundamental data structure. Each heap
 * node contains only the heap priority value (i.e., the cost of the RR node)
 * and the index of the RR node. The size of each heap node is minimized to
 * ensure that the heap is cache-friendly and to make the initialization and
 * copying of heap nodes efficient.
 */
struct HeapNode {
    ///@brief The priority value or cost used to sort heap. For the timing-driven router
    /// this is the total_cost (i.e., backward_path_cost + expected cost to the target).
    HeapNodePriority prio;
    ///@brief The RR node index associated with the cost.
    HeapNodeId node;
};

/**
 * @brief The comparison function object used to sort heap, following the STL style.
 */
struct HeapNodeComparator {
    bool operator()(const HeapNode& u, const HeapNode& v) {
        return u.prio > v.prio;
    }
};

/**
 * @brief Interface to heap used for router optimization.
 */
class HeapInterface {
  public:
    virtual ~HeapInterface() {}

    /**
     * @brief Initializes heap storage based on the size of the device.
     *
     * @note
     * This method **must** be invoked at least once prior to the
     * following methods being called:<BR>
     *  - try_pop<BR>
     *  - add_to_heap<BR>
     *  - push_back<BR>
     *  - build_heap<BR>
     *  - empty_heap<BR>
     *  - is_empty_heap<BR>
     *
     *  @param grid The FPGA device grid
     */
    virtual void init_heap(const DeviceGrid& grid) = 0;

    /**
     * @brief Pop the head (smallest element) of the heap. Return true if the pop
     * succeeds; otherwise (if the heap is empty), return false.
     *
     * @param heap_node The reference to a location to store the popped heap node.
     */
    virtual bool try_pop(HeapNode& heap_node) = 0;

    /**
     * @brief Add HeapNode to heap, preserving heap property.
     *
     * @param heap_node The element to add.
     */
    virtual void add_to_heap(const HeapNode& heap_node) = 0;

    /**
     * @brief Add HeapNode to heap, however does not preserve heap property.
     *
     * @param hptr The element to insert.
     */
    virtual void push_back(const HeapNode& heap_node) = 0;

    /**
     * @brief Restore the heap property.
     *
     * @details
     * This is useful in conjunction with HeapInterface::push_back when adding
     * multiple heap elements.
     */
    virtual void build_heap() = 0;

    /**
     * @brief Is the heap valid?
     */
    virtual bool is_valid() const = 0;

    /**
     * @brief Empty all items from the heap.
     */
    virtual void empty_heap() = 0;

    /**
     * @brief Is the heap empty?
     */
    virtual bool is_empty_heap() const = 0;
};

enum class e_heap_type {
    INVALID_HEAP = 0,
    BINARY_HEAP,
    FOUR_ARY_HEAP,
};

/**
 * @brief Heap factory.
 */
std::unique_ptr<HeapInterface> make_heap(e_heap_type);

#pragma once

#ifndef NO_SERVER

#include <string>
#include <memory>
#include <chrono>

#include "telegramheader.h"
#include "commcmd.h"

namespace server {

/**
 * @brief Implements the server task.
 * 
 * This structure aids in encapsulating the client request, request result, and result status.
 * It generates a JSON data structure to be sent back to the client as a response.
 */
class Task {
  public:
    /**
     * @brief Constructs a new Task object.
     * 
     * @param job_id The ID of the job associated with the task.
     * @param cmd The command ID (see @ref comm::CMD) associated with the task.
     * @param options Additional options for the task (default: empty string).
     */
    Task(int job_id, comm::CMD cmd, const std::string& options = "");

    Task(const Task&) = delete;
    Task& operator=(const Task&) = delete;

    /**
     * @brief Gets the job ID associated with the task.
     * 
     * @return The job ID.
     */
    int job_id() const { return m_job_id; }

    /**
     * @brief Gets the command ID associated with the task.
     * 
     * @return The command ID (see @ref comm::CMD).
     */
    comm::CMD cmd() const { return m_cmd; }

    /**
     * @brief Removes the specified number of bytes from the response buffer.
     * 
     * This method removes the specified number of bytes from the beginning of the response buffer.
     * It is typically used after sending a response to discard the bytes that have been sent.
     * 
     * @param bytes_sent_num The number of bytes to remove from the response buffer.
     */
    void chop_num_sent_bytes_from_response_buffer(std::size_t bytes_sent_num);

    /**
     * @brief Checks if the options of this task match the options of another task.
     * 
     * This method compares the options of this task with the options of another task
     * and returns true if they match, otherwise returns false.
     * 
     * @param other The other task to compare options with.
     * @return True if the options match, false otherwise.
     */
    bool options_match(const std::unique_ptr<Task>& other);

    /**
     * @brief Retrieves the response buffer.
     * 
     * This method returns a constant reference to the response buffer, which contains the data after task execution.
     * 
     * @return A constant reference to the response buffer.
     */
    const std::string& response_buffer() const { return m_response_buffer; }

    /**
     * @brief Checks if the task has finished execution.
     * 
     * This method returns true if the task has finished execution; otherwise, it returns false.
     * 
     * @return True if the task has finished execution, false otherwise.
     */
    bool is_finished() const { return m_is_finished; }

    /**
     * @brief Checks if the task has encountered an error.
     * 
     * This method returns true if the task has encountered an error; otherwise, it returns false.
     * 
     * @return True if the task has encountered an error, false otherwise.
     */
    bool has_error() const { return !m_error.empty(); }

    /**
     * @brief Retrieves the error message associated with the task.
     * 
     * This method returns the error message associated with the task, if any.
     * 
     * @return A constant reference to the error message string.
     */
    const std::string& error() const { return m_error; }

    /**
     * @brief Retrieves the original number of response bytes.
     * 
     * This method returns the original number of response bytes before any chopping operation.
     * 
     * @return The original number of response bytes.
     */
    std::size_t orig_reponse_bytes_num() const { return m_orig_reponse_bytes_num; }

    /**
     * @brief Checks if the response has been fully sent.
     * 
     * This method returns true if the entire response has been successfully sent, 
     * otherwise it returns false.
     * 
     * @return True if the response has been fully sent, false otherwise.
     */
    bool is_response_fully_sent() const { return m_is_response_fully_sent; }

    /**
     * @brief Marks the task as failed with the specified error message.
     * 
     * This method sets the task's error message to the provided error string, 
     * indicating that the task has failed.
     * 
     * @param error The error message describing the reason for the task's failure.
     */
    void set_fail(const std::string& error);

    /**
     * @brief Marks the task as successfully completed.
     */
    void set_success();

    /**
     * @brief Marks the task as successfully completed with the specified result.
     * 
     * This method marks the task as successfully completed and stores the result.
     * It takes an rvalue reference to a string, allowing for efficient move semantics.
     * 
     * @param result An rvalue reference to a string describing the result of the task execution.
     *               The content of this string will be moved into the task's result storage.
     */
    void set_success(std::string&& result);

    /**
     * @brief Generates a string containing information about the task.
     * 
     * This method generates a string containing information about the task,
     * including its identifier, command, options, and optionally its duration.
     * 
     * @param skip_duration If true, the duration information will be omitted from the string.
     * 
     * @return A string containing information about the task.
     */
    std::string info(bool skip_duration = false) const;

    /**
     * @brief Retrieves the TelegramHeader associated with the task.
     * 
     * This method returns a reference to the TelegramHeader associated with the task.
     * 
     * @return A reference to the TelegramHeader associated with the task.
     */
    const comm::TelegramHeader& telegram_header() const { return m_telegram_header; }

    /**
     * @brief Retrieves the options associated with the task.
     * 
     * This method returns a reference to the options string associated with the task.
     * 
     * @return A reference to the options string associated with the task.
     */
    const std::string& options() const { return m_options; }

  private:
    int m_job_id = -1;
    comm::CMD m_cmd = comm::CMD::NONE;
    std::string m_options;
    std::string m_result;
    std::string m_error;
    bool m_is_finished = false;
    comm::TelegramHeader m_telegram_header;
    std::string m_response_buffer;
    std::size_t m_orig_reponse_bytes_num = 0;
    bool m_is_response_fully_sent = false;

    std::chrono::high_resolution_clock::time_point m_creation_time;

    int64_t time_ms_elapsed() const;

    void bake_response();
};
using TaskPtr = std::unique_ptr<Task>;

} // namespace server

#endif /* NO_SERVER */

