1	/********************************************************************
2	 * MultiQueue Implementation
3	 *
4	 * Originally authored by Guozheng Zhang, Gilead Posluns, and Mark C. Jeffrey
5	 * Published at the 36th ACM Symposium on Parallelism in Algorithms and
6	 * Architectures (SPAA), June 2024
7	 *
8	 * Original source: https://github.com/mcj-group/cps
9	 *
10	 * This implementation and interface has been modified from the original to:
11	 *   - Support queue draining functionality
12	 *   - Enable integration with the VTR project
13	 *
14	 * The MultiQueue data structure provides an efficient concurrent priority
15	 * queue implementation designed for parallel processing applications.
16	 *
17	 * Modified: February 2025
18	 ********************************************************************/
19	
20	#pragma once
21	
22	#include <cstdlib>
23	#include <iostream>
24	#include <limits>
25	#include <optional>
26	#include <vector>
27	#include <algorithm>
28	#include <atomic>
29	#include <thread>
30	#include <cassert>
31	#include <thread>
32	#include "d_ary_heap.tpp"
33	
34	// Cache line size in bytes. Hardcoded to 64 since that is correct for all
35	// x86/x86-64 CPUs (32B and 128B have never shipped). Apple Silicon uses 128B,
36	// but VTR does not currently target it.
37	//
38	// The idiomatic C++17 alternative is std::hardware_destructive_interference_size
39	// from <new>, which queries the target at compile time. However:
40	//   1. GCC warns about it (-Winterference-size) unless the warning is suppressed
41	//      with a #pragma GCC diagnostic, which we are willing to do.
42	//   2. The interface is not available in GCC < 12 (e.g. GCC 11 on Ubuntu 22.04
43	//      Jammy, one of our supported build environments), so it cannot be used
44	//      portably until that toolchain is retired.
45	#define CACHELINE 64
46	
47	#define MQ_IO_ENABLE_CLEAR_FOR_POP
48	
49	template<
50	    unsigned D,
51	    typename PQElement,
52	    typename Comparator,
53	    typename PrioType>
54	class MultiQueueIO {
55	    using PQ = customized_d_ary_priority_queue<D, PQElement, std::vector<PQElement>, Comparator>;
56	    Comparator compare;
57	
58	    // Special value used to signify that there is no 'min' element in a PQ
59	    // container. The user should ensure that they do not use this priority
60	    // while using the MQ.
61	    static constexpr PrioType EMPTY_PRIO = std::numeric_limits<PrioType>::max();
62	
63	    struct alignas(CACHELINE) PQContainer {
64	        uint64_t pushes = 0;
65	        uint64_t pops = 0;
66	        PQ pq;
67	        std::atomic_flag queueLock = ATOMIC_FLAG_INIT;
68	        std::atomic<PrioType> min{EMPTY_PRIO};
69	
70	        void lock() {
71	            while (queueLock.test_and_set(std::memory_order_acquire))
72	                ;
73	        }
74	        bool try_lock() { return queueLock.test_and_set(std::memory_order_acquire); }
75	        void unlock() { queueLock.clear(std::memory_order_release); }
76	    };
77	
78	    std::vector<
79	        PQContainer
80	        // FIXME: Disabled this due to VTR not using Boost. There is a C++ way
81	        //        of doing this, but it requires making an aligned allocator
82	        //        class. May be a good idea to add to VTR util in the future.
83	        //        Should profile for performance first; may not be worth it.
84	        // , boost::alignment::aligned_allocator<PQContainer, CACHELINE>
85	        >
86	        queues;
87	    uint64_t NUM_QUEUES;
88	
89	    // Termination:
90	    //  - numIdle records the number of threads that believe
91	    //    there are no more work to do.
92	    //  -numEmpty records number of queues that are empty
93	    uint64_t threadNum;
94	    std::atomic<uint64_t> numIdle{0};
95	    std::atomic<uint64_t> numEmpty;
96	#ifdef MQ_IO_ENABLE_CLEAR_FOR_POP
97	    std::atomic<PrioType> minPrioForPop{std::numeric_limits<PrioType>::max()};
98	#endif
99	
100	    uint64_t batchSize;
101	
102	  public:
103	    MultiQueueIO(uint64_t numQueues, uint64_t numThreads, uint64_t batch)
104	        : queues(numQueues)
105	        , NUM_QUEUES(numQueues)
106	        , threadNum(numThreads)
107	        , numEmpty(numQueues)
108	        , batchSize(batch) {
109	        assert((numQueues >= 2) && "numQueues must be set >= 2");
110	    }
111	
112	    uint64_t ThreadLocalRandom() {
113	        // static thread_local std::mt19937_64 generator;
114	        // std::uniform_real_distribution<> distribution(min,max);
115	        // return distribution(generator);
116	        static uint64_t modMask = NUM_QUEUES - 1;
117	        static thread_local uint64_t x = std::hash<std::thread::id>{}(std::this_thread::get_id());
118	        uint64_t z = (x += UINT64_C(0x9E3779B97F4A7C15));
119	        z = (z ^ (z >> 30)) * UINT64_C(0xBF58476D1CE4E5B9);
120	        z = (z ^ (z >> 27)) * UINT64_C(0x94D049BB133111EB);
121	        return (z ^ (z >> 31)) & modMask;
122	    }
123	
124	    inline void push(PQElement item) {
125	        uint64_t queue;
126	        while (true) {
127	            queue = ThreadLocalRandom();
128	            if (!queues[queue].try_lock()) break;
129	        }
130	        auto& q = queues[queue];
131	        q.pushes++;
132	        if (q.pq.empty())
133	            numEmpty.fetch_sub(1, std::memory_order_relaxed);
134	        q.pq.push(item);
135	        q.min.store(
136	            q.pq.size() > 0
137	                ? std::get<0>(q.pq.top())
138	                : EMPTY_PRIO,
139	            std::memory_order_release);
140	        q.unlock();
141	    }
142	
143	    inline void pushBatch(uint64_t size, PQElement* items) {
144	        uint64_t queue;
145	        while (true) {
146	            queue = ThreadLocalRandom();
147	            if (!queues[queue].try_lock()) break;
148	        }
149	        auto& q = queues[queue];
150	        q.pushes += size;
151	        if (q.pq.empty())
152	            numEmpty.fetch_sub(1, std::memory_order_relaxed);
153	        for (uint64_t i = 0; i < size; i++) {
154	            q.pq.push(items[i]);
155	        }
156	        q.min.store(
157	            q.pq.size() > 0
158	                ? std::get<0>(q.pq.top())
159	                : EMPTY_PRIO,
160	            std::memory_order_release);
161	        q.unlock();
162	    }
163	
164	    // Simplified Termination detection idea from the 2021 MultiQueue paper:
165	    // Repeatedly try popping and stop when numIdle >= threadNum,
166	    // That is, stop when all threads agree that there are no more work
167	    inline std::optional<PQElement> tryPop() {
168	        auto item = pop();
169	        if (item) return item;
170	
171	        // increment count and keep on trying to pop
172	        uint64_t num = numIdle.fetch_add(1, std::memory_order_relaxed) + 1;
173	        do {
174	            item = pop();
175	            if (item) break;
176	            if (num >= threadNum) return {};
177	
178	            num = numIdle.load(std::memory_order_relaxed);
179	
180	        } while (true);
181	
182	        numIdle.fetch_sub(1, std::memory_order_relaxed);
183	        return item;
184	    }
185	
186	#ifdef MQ_IO_ENABLE_CLEAR_FOR_POP
187	    inline void setMinPrioForPop(PrioType newMinPrio) {
188	        PrioType oldMinPrio = minPrioForPop.load(std::memory_order_relaxed);
189	        while (compare({oldMinPrio, 0}, {newMinPrio, 0}) /* old > new */ && !minPrioForPop.compare_exchange_weak(oldMinPrio, newMinPrio))
190	            ;
191	    }
192	#endif
193	
194	    inline std::optional<PQElement> pop() {
195	        uint64_t poppingQueue = NUM_QUEUES;
196	        while (true) {
197	            // Pick the higher priority max of queue i and j
198	            uint64_t i = ThreadLocalRandom();
199	            uint64_t j = ThreadLocalRandom();
200	            while (j == i) {
201	                j = ThreadLocalRandom();
202	            }
203	
204	            PrioType minI = queues[i].min.load(std::memory_order_acquire);
205	            PrioType minJ = queues[j].min.load(std::memory_order_acquire);
206	
207	            if (minI == EMPTY_PRIO && minJ == EMPTY_PRIO) {
208	                uint64_t emptyQueues = numEmpty.load(std::memory_order_relaxed);
209	                if (emptyQueues >= queues.size())
210	                    break;
211	                else
212	                    continue;
213	            }
214	
215	            if (minI != EMPTY_PRIO && minJ != EMPTY_PRIO) {
216	                poppingQueue = compare({minJ, 0}, {minI, 0}) ? i : j;
217	            } else if (minJ == EMPTY_PRIO) {
218	                poppingQueue = i;
219	            } else {
220	                poppingQueue = j;
221	            }
222	            if (queues[poppingQueue].try_lock()) continue;
223	            auto& q = queues[poppingQueue];
224	            if (!q.pq.empty()) {
225	#ifdef MQ_IO_ENABLE_CLEAR_FOR_POP
226	                PrioType minPrio = minPrioForPop.load(std::memory_order_acquire);
227	                if (compare(q.pq.top(), {minPrio, 0})) {
228	                    q.pq.clear();
229	                    // do not add `q.pops` on purpose
230	                    numEmpty.fetch_add(1, std::memory_order_relaxed);
231	                    q.min.store(EMPTY_PRIO, std::memory_order_release);
232	                } else {
233	#endif
234	                    PQElement retItem = q.pq.top();
235	                    q.pq.pop();
236	                    q.pops++;
237	                    if (q.pq.empty())
238	                        numEmpty.fetch_add(1, std::memory_order_relaxed);
239	                    q.min.store(
240	                        q.pq.size() > 0
241	                            ? std::get<0>(q.pq.top())
242	                            : EMPTY_PRIO,
243	                        std::memory_order_release);
244	                    q.unlock();
245	                    return retItem;
246	#ifdef MQ_IO_ENABLE_CLEAR_FOR_POP
247	                }
248	#endif
249	            }
250	            q.unlock();
251	        }
252	        return {};
253	    }
254	
255	    inline std::optional<uint64_t> tryPopBatch(PQElement* ret) {
256	        auto item = popBatch(ret);
257	        if (item) return item;
258	
259	        // increment count and keep on trying to pop
260	        uint64_t num = numIdle.fetch_add(1, std::memory_order_relaxed) + 1;
261	        do {
262	            item = popBatch(ret);
263	            if (item) break;
264	            if (num >= threadNum) return {};
265	
266	            num = numIdle.load(std::memory_order_relaxed);
267	
268	        } while (true);
269	
270	        numIdle.fetch_sub(1, std::memory_order_relaxed);
271	        return item;
272	    }
273	
274	    inline std::optional<uint64_t> popBatch(PQElement* ret) {
275	        uint64_t poppingQueue = NUM_QUEUES;
276	        while (true) {
277	            // Pick the higher priority max of queue i and j
278	            uint64_t i = ThreadLocalRandom();
279	            uint64_t j = ThreadLocalRandom();
280	            while (j == i) {
281	                j = ThreadLocalRandom();
282	            }
283	
284	            PrioType minI = queues[i].min.load(std::memory_order_acquire);
285	            PrioType minJ = queues[j].min.load(std::memory_order_acquire);
286	
287	            if (minI == EMPTY_PRIO && minJ == EMPTY_PRIO) {
288	                uint64_t emptyQueues = numEmpty.load(std::memory_order_relaxed);
289	                if (emptyQueues >= queues.size())
290	                    break;
291	                else
292	                    continue;
293	            }
294	
295	            if (minI != EMPTY_PRIO && minJ != EMPTY_PRIO) {
296	                poppingQueue = compare({minJ, 0}, {minI, 0}) ? i : j;
297	            } else if (minJ == EMPTY_PRIO) {
298	                poppingQueue = i;
299	            } else {
300	                poppingQueue = j;
301	            }
302	            if (queues[poppingQueue].try_lock()) continue;
303	            auto& q = queues[poppingQueue];
304	            if (q.pq.empty()) {
305	                q.unlock();
306	                continue;
307	            }
308	
309	            uint64_t num = 0;
310	            for (num = 0; num < batchSize; num++) {
311	                if (q.pq.empty()) break;
312	                ret[num] = q.pq.top();
313	                q.pq.pop();
314	            }
315	            q.pops += num;
316	            if (q.pq.empty())
317	                numEmpty.fetch_add(1, std::memory_order_relaxed);
318	            q.min.store(
319	                q.pq.size() > 0
320	                    ? std::get<0>(q.pq.top())
321	                    : EMPTY_PRIO,
322	                std::memory_order_release);
323	            q.unlock();
324	            if (num == 0) continue;
325	
326	            return num;
327	        }
328	        return {};
329	    }
330	
331	    inline uint64_t
332	    getQueueOccupancy() const {
333	        uint64_t maxOccupancy = 0;
334	        for (uint64_t i = 0; i < NUM_QUEUES; i++) {
335	            maxOccupancy = std::max(maxOccupancy, queues[i].pq.size());
336	        }
337	        return maxOccupancy;
338	    }
339	
340	    // Get the number of pushes to all queues.
341	    // Note: this is not lock protected.
342	    inline uint64_t getNumPushes() const {
343	        uint64_t totalPushes = 0;
344	        for (uint64_t i = 0; i < NUM_QUEUES; i++) {
345	            totalPushes += queues[i].pushes;
346	        }
347	        return totalPushes;
348	    }
349	
350	    // Get the number of pops to all queues.
351	    // Note: this is not lock protected.
352	    inline uint64_t getNumPops() const {
353	        uint64_t totalPops = 0;
354	        for (uint64_t i = 0; i < NUM_QUEUES; i++) {
355	            totalPops += queues[i].pops;
356	        }
357	        return totalPops;
358	    }
359	
360	    inline void stat() const {
361	        std::cout << "total pushes " << getNumPushes() << "\n";
