178	        VTR_LOG("starting server");
179	        m_is_running.store(true);
180	        m_thread = std::thread(&GateIO::start_listening, this);
181	        // QApplication is guaranteed to exist by the time start() is called
182	        // (vpr_init_graphics runs before vpr_init_server). Starting the timer
183	        // here avoids the "Timers can only be used with threads started with
184	        // QThread" warning that firing it in the constructor would cause.
185	        m_updateTimer.setInterval(SERVER_UPDATE_INTERVAL_MS);
186	        QObject::connect(&m_updateTimer, &QTimer::timeout, &m_updateTimer, []() {
187	            server::update(application);
188	        });
189	        m_updateTimer.start();
190	    }
