202	void GateIO::take_received_tasks(std::vector<TaskPtr>& tasks) {
203	    std::unique_lock<std::mutex> lock(m_tasks_mutex);
204	    for (TaskPtr& task : m_received_tasks) {
205	        m_logger.queue(LogLevel::Debug, "move task id=", task->job_id(), "for processing");
206	        tasks.push_back(std::move(task));
207	    }
208	    m_received_tasks.clear();
209	}
