211	void GateIO::move_tasks_to_send_queue(std::vector<TaskPtr>& tasks) {
212	    std::unique_lock<std::mutex> lock(m_tasks_mutex);
213	    for (TaskPtr& task : tasks) {
214	        m_logger.queue(LogLevel::Debug, "move task id=", task->job_id(), "finished", (task->has_error() ? "with error" : "successfully"), task->error(), "to send queue");
215	        m_send_tasks.push_back(std::move(task));
216	    }
217	    tasks.clear();
218	}
