220	void GateIO::start_listening() {
221	#ifdef ENABLE_CLIENT_ALIVE_TRACKER
222	    std::unique_ptr<ClientAliveTracker> client_alive_tracker_ptr =
223	        std::make_unique<ClientAliveTracker>(std::chrono::milliseconds{5000}, std::chrono::milliseconds{20000});
224	#else
225	    std::unique_ptr<ClientAliveTracker> client_alive_tracker_ptr;
226	#endif
227	
228	    comm::TelegramBuffer telegram_buff;
229	    std::vector<comm::TelegramFramePtr> telegram_frames;
230	
231	    sockpp::initialize();
232	    sockpp::tcp6_acceptor tcp_server(m_port_num);
233	    tcp_server.set_non_blocking(true);
234	
235	    if (tcp_server) {
236	        m_logger.queue(LogLevel::Info, "open server, port=", m_port_num);
237	    } else {
238	        m_logger.queue(LogLevel::Info, "fail to open server, port=", m_port_num);
239	    }
240	
241	    std::optional<sockpp::tcp6_socket> client_opt;
242	
243	    std::string received_message;
244	    received_message.resize(CHUNK_MAX_BYTES_NUM);
245	
246	    /// comm event loop
247	    while (m_is_running.load()) {
248	        bool is_communication_problem_detected = false;
249	
250	        if (!client_opt) {
251	            ActivityStatus status = check_client_connection(tcp_server, client_opt, m_logger);
252	            if (status == ActivityStatus::CLIENT_ACTIVITY) {
253	                if (client_alive_tracker_ptr) {
254	                    client_alive_tracker_ptr->reset();
255	                }
256	            }
257	        }
258	
259	        if (client_opt) {
260	            sockpp::tcp6_socket& client = client_opt.value(); // shortcut
261	
262	            /// handle sending
263	            ActivityStatus status = handle_sending_data(client, m_tasks_mutex, m_send_tasks, m_logger);
264	            handle_activity_status(status, client_alive_tracker_ptr, is_communication_problem_detected);
265	
266	            /// handle receiving
267	            status = handle_receiving_data(client, telegram_buff, received_message, m_logger);
268	            handle_activity_status(status, client_alive_tracker_ptr, is_communication_problem_detected);
269	
270	            /// handle telegrams
271	            status = handle_telegrams(telegram_frames, telegram_buff, m_tasks_mutex, m_received_tasks, m_logger);
272	            handle_activity_status(status, client_alive_tracker_ptr, is_communication_problem_detected);
273	
274	            // forward telegramBuffer errors
275	            std::vector<std::string> telegram_buffer_errors;
276	            telegram_buff.take_errors(telegram_buffer_errors);
277	            for (const std::string& error : telegram_buffer_errors) {
278	                m_logger.queue(LogLevel::Info, error);
279	            }
280	
281	            /// handle client alive tracker
282	            status = handle_client_alive_tracker(client, client_alive_tracker_ptr, m_logger);
283	            handle_activity_status(status, client_alive_tracker_ptr, is_communication_problem_detected);
284	
285	            /// handle communication problem
286	            if (is_communication_problem_detected) {
287	                client_opt = std::nullopt;
288	                if (!telegram_buff.empty()) {
289	                    m_logger.queue(LogLevel::Debug, "clear telegramBuff");
290	                    telegram_buff.clear();
291	                }
292	            }
293	        }
294	
295	        std::this_thread::sleep_for(std::chrono::milliseconds{LOOP_INTERVAL_MS});
296	    }
297	}
